var ticketServices={checkTicketAvailability:function(uuid,payload){return httpClient.processRequest("get","/check-ticket-availability?eventuuid="+uuid+"&ticketData="+payload)},createTickets:function(uuid){return httpClient.processRequest("post","/create-tickets?eventuuid="+uuid)},allocateTicket:function(eventUuid,ticketUuid,payload){return httpClient.processRequest("put","/allocate-ticket?eventUUID="+eventUuid+"&ticketUUID="+ticketUuid+"&ticketData="+payload)}};